# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_issue_11534","kind":"function","src_hash":"c7c55703ddd2ed58","in":{"base":"Any"},"out":{"base":"Any","pred":"result satisfies: solveset(eq1, x, S.Reals) == sol1 and solveset(eq2, x, S.Reals) == sol2"},"spec":{"lhs":"test_issue_11534()","rhs":"solveset(eq1, x, S.Reals) == sol1 and solveset(eq2, x, S.Reals) == sol2","over":{"base":"Any"},"name":"test_issue_11534_correct"},"guarantee":"solveset(eq1, x, S.Reals) == sol1; solveset(eq2, x, S.Reals) == sol2","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_issue_11534_correct","statement":"Path(test_issue_11534(x), solveset(eq1, x, S.Reals) == sol1; solveset(eq2, x, S.Reals) == sol2)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"348cefbb69767e91","spec_source":"static","formal_spec":{"source":"static","strength":"formal","ensures":["solveset(eq1, x, S.Reals) == sol1","solveset(eq2, x, S.Reals) == sol2"],"pure":true},"c4_verdict":{"valid":true,"n_vcs":1,"n_verified":0,"n_assumed":1,"n_failed":0,"trust_level":"LIBRARY_ASSUMED","compile_ms":0.2,"verdict_class":"assumed","binding":true}}
def test_issue_11534():
    # eq1 and eq2 should not have the same solutions because squaring both
    # sides of the radical equation introduces a spurious solution branch.
    # The equations have a symbolic parameter y and it is easy to see that for
    # y != 0 the solution s1 will not be valid for eq1.
    x = Symbol('x', real=True)
    y = Symbol('y', real=True)
    eq1 = -y + x/sqrt(-x**2 + 1)
    eq2 = -y**2 + x**2/(-x**2 + 1)

    # We get a ConditionSet here because s1 works in eq1 if y is equal to zero
    # although not for any other value of y. That case is redundant though
    # because if y=0 then s1=s2 so the solution for eq1 could just be returned
    # as s2 - {-1, 1}. In fact we have
    #   |y/sqrt(y**2 + 1)| < 1
    # So the complements are not needed either. The ideal output here would be
    #   sol1 = s2
    #   sol2 = s1 | s2.
    s1, s2 = FiniteSet(-y/sqrt(y**2 + 1)), FiniteSet(y/sqrt(y**2 + 1))
    cset = ConditionSet(x, Eq(eq1, 0), s1)
    sol1 = (s2 - {-1, 1}) | (cset - {-1, 1})
    sol2 = (s1 | s2) - {-1, 1}

    assert solveset(eq1, x, S.Reals) == sol1
    assert solveset(eq2, x, S.Reals) == sol2


