# @cctt_verify {"v":2,"sym":"sympy.solvers.tests.test_solveset.test_issue_19144","kind":"function","src_hash":"10048b3170f404ff","in":{"base":"Any"},"out":{"base":"Any","pred":"result satisfies: soln_eq1 == soln_expr1 == soln1 and soln_eq2 == soln_expr2 == soln2 and nonlinsolve([Eq(x + 1 / x, 1 / x)], [x]) == FiniteSet((S.EmptySet,))"},"spec":{"lhs":"test_issue_19144()","rhs":"soln_eq1 == soln_expr1 == soln1 and soln_eq2 == soln_expr2 == soln2 and nonlinsolve([Eq(x + 1 / x, 1 / x)], [x]) == FiniteSet((S.EmptySet,))","over":{"base":"Any"},"name":"test_issue_19144_correct"},"guarantee":"soln_eq1 == soln_expr1 == soln1; soln_eq2 == soln_expr2 == soln2; nonlinsolve([Eq(x + 1 / x, 1 / x)], [x]) == FiniteSet((S.EmptySet,))","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.solvers.tests.test_solveset.test_issue_19144_correct","statement":"Path(test_issue_19144(x), soln_eq1 == soln_expr1 == soln1; soln_eq2 == soln_expr2 == soln2; nonlinsolve([Eq(x + 1 / x, 1 / x)], [x]) == FiniteSet((S.EmptySet,)))"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"4841a76464dddb2b","spec_source":"static","formal_spec":{"source":"static","strength":"formal","ensures":["soln_eq1 == soln_expr1 == soln1","soln_eq2 == soln_expr2 == soln2","nonlinsolve([Eq(x + 1 / x, 1 / x)], [x]) == FiniteSet((S.EmptySet,))"],"pure":true},"c4_verdict":{"valid":true,"n_vcs":1,"n_verified":0,"n_assumed":1,"n_failed":0,"trust_level":"LIBRARY_ASSUMED","compile_ms":0.4,"verdict_class":"assumed","binding":true}}
def test_issue_19144():
    # test case 1
    expr1 = [x + y - 1, y**2 + 1]
    eq1 = [Eq(i, 0) for i in expr1]
    soln1 = {(1 - I, I), (1 + I, -I)}
    soln_expr1 = nonlinsolve(expr1, [x, y])
    soln_eq1 = nonlinsolve(eq1, [x, y])
    assert soln_eq1 == soln_expr1 == soln1
    # test case 2 - with denoms
    expr2 = [x/y - 1, y**2 + 1]
    eq2 = [Eq(i, 0) for i in expr2]
    soln2 = {(-I, -I), (I, I)}
    soln_expr2 = nonlinsolve(expr2, [x, y])
    soln_eq2 = nonlinsolve(eq2, [x, y])
    assert soln_eq2 == soln_expr2 == soln2
    # denominators that cancel in expression
    assert nonlinsolve([Eq(x + 1/x, 1/x)], [x]) == FiniteSet((S.EmptySet,))


